export const PortfolioSchema = z.object({
  id: z.string(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
  createdById: z.string().nullable(),
  name: z.string(),
  /**
   * How often should we harvest for the portfolio
   */
  harvestCycleWeeks: z.number().int(),
  /**
   * How much $ amount does a single share need to exceed to be a valid harvest share (i.e. shares with a p/l lower we shouldnt even care about)
   */
  harvestShareDollarThreshold: z.instanceof(Prisma.Decimal, { message: "Field 'harvestShareDollarThreshold' must be a Decimal. Location: ['Models', 'Portfolio']"}),
  /**
   * As we iterate through different tickets to build a harvest, how much $ should we target before moving to the next one
   */
  harvestTickerBucketDollarSizeLong: z.instanceof(Prisma.Decimal, { message: "Field 'harvestTickerBucketDollarSizeLong' must be a Decimal. Location: ['Models', 'Portfolio']"}),
  /**
   * How much is a valid bucket (otherwise a ticker is considered 'slop')
   */
  harvestTickerBucketLowerLimitLong: z.instanceof(Prisma.Decimal, { message: "Field 'harvestTickerBucketLowerLimitLong' must be a Decimal. Location: ['Models', 'Portfolio']"}),
  /**
   * As we iterate through different tickets to build a harvest, how much $ should we target before moving to the next one
   */
  harvestTickerBucketDollarSizeShort: z.instanceof(Prisma.Decimal, { message: "Field 'harvestTickerBucketDollarSizeShort' must be a Decimal. Location: ['Models', 'Portfolio']"}),
  /**
   * How much is a valid bucket (otherwise a ticker is considered 'slop')
   */
  harvestTickerBucketLowerLimitShort: z.instanceof(Prisma.Decimal, { message: "Field 'harvestTickerBucketLowerLimitShort' must be a Decimal. Location: ['Models', 'Portfolio']"}),
})

export type Portfolio = z.infer<typeof PortfolioSchema>

